SELECT "" AS [timestamp], 15000 AS [Entry No_], "" AS [Journal Batch Name], 0 AS [Line No], #9/2/2025# AS [Registering Date], [DDT_Picking Header].[Location Code], "SPEDIZIONE" AS [Zone code], "M02S01" AS [bin code], "" AS dESCRITPION, [DDT_Picking Line].No_ AS [iTEM NO_], -Val([ddt_picking Line.QUANTITY]) AS qUANTITY_, -Val([ddt_picking line.quantity]) AS [Qty_ (base)], 87380 AS [Source Type], 0 AS [source subtype], [DDT_Picking Header].nO_ AS [Source no_], [DDT_Picking Line].[LINE NO_] AS [Source Line No_], 0 AS [source subline no_], 28 AS [Source Document], "VENDITE" AS [Source code], "" AS [Reason code], "" AS [No_ Series], "SPEDIZIONE" AS [bin Type Code], 0 AS Cubage, 0 AS Weight, "" AS [Journal Template Name], [Warehouse Shipment Line].NO_ AS [Whse_ Document No_], 2 AS [Whse_ Document Type], [Warehouse Shipment Line].[LINE NO_] AS [Whse_ Document Line No_], 0 AS [Entry Type], 5 AS [Reference Document], [DDT_Picking Line].[Shipment No_] AS [Reference No_], "FEBOS\AIVE" AS [User Id], "" AS [Variant Code], 1 AS [Qty_ Per Unit of Measure], "PA" AS [Unit of measure code], "" AS [Serial No_], "" AS [Lot No_], #1/1/1753# AS [Warranty Date], #1/1/1753# AS [Expiration Date], "" AS [Phys Invt COunting Period Code], 0 AS [Phys Invt COunting Period Type], 0 AS Dedicated, [DDT_Picking Header].[Selling Season Code], [DDT_Picking Line].[Constant Assortment Var_Grp_], [DDT_Picking Line].[Constant Variable Code], [DDT_Picking Line].[Assortment Code], "" AS [Package Code], "" AS [Model Item No_], "" AS [Variable Group 01], "" AS [Variable Code 01], "" AS [Variable Group 02], "" AS [Variable Code 02], "" AS [Variable Group 03], "" AS [Variable Code 03], "" AS [Variable Group 04], "" AS [Variable Code 04], "" AS [Variable Group 05], "" AS [Variable Code 05], [DDT_Picking Line].[Model Code], [DDT_Picking Line].[Collection Code], [DDT_Picking Line].[Season Code], [DDT_Picking Line].[Line Code], [DDT_Picking Line].[Brand Code], [DDT_Picking Line].[Commercial Kit Code] INTO WMS_ExportPerGorbes_FuturoImportExcel
FROM [Warehouse Shipment Line] INNER JOIN ([DDT_Picking Line] INNER JOIN [DDT_Picking Header] ON ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) AND ([DDT_Picking Line].[Document Type] = [DDT_Picking Header].[Document Type])) ON ([Warehouse Shipment Line].[Source Line No_] = [DDT_Picking Line].[Line No_]) AND ([Warehouse Shipment Line].[Source No_] = [DDT_Picking Line].[Document No_])
WHERE ((([DDT_Picking Line].TYPE)=20) AND (([DDT_Picking Header].NO_)="SPD-25/10581"));

